  _setFeeAggregator(params.feeAggregator);

  if (params.minPriceMultiplier == 0) {
    revert Errors.InvalidZeroValue();
  }

  i_minPriceMultiplier = params.minPriceMultiplier;

  emit MinPriceMultiplierSet(params.minPriceMultiplier);

